export default {
  getMatches() {
    const adopter = getAdopterProfile.data;
    const pets = getAllPetsForMatching.data;

    return pets.map(pet => {
      let score = 0;
      const temp = pet.temperament ? pet.temperament.toLowerCase() : "";

      // +3 if species matches preference
      if (adopter.preferredSpecies && 
          pet.species.toLowerCase() === adopter.preferredSpecies.toLowerCase()) {
        score += 3;
      }

      // +2 if house and dog
      if (adopter.livingEnvironment === "HOUSE" && pet.species === "Dog") {
        score += 2;
      }

      // +1 if has children and pet is gentle/friendly
      if (adopter.hasChildren && (temp.includes("gentle") || temp.includes("friendly"))) {
        score += 1;
      }

      // +1 if has other pets and pet is sociable/calm
      if (adopter.hasOtherPets && (temp.includes("sociable") || temp.includes("calm"))) {
        score += 1;
      }

      return { ...pet, matchScore: score };
    })
    .sort((a, b) => b.matchScore - a.matchScore);
  }
}

