export default {
	getMessagesWithNames() {
		const inbox = getInbox.data;
		const sent = getSent.data;
		const adopters = getAllAdopters.data;
		const providers = getAllProviders.data;

		const getName = (userId) => {
			const adopter = adopters.find(a => a.userId === userId);
			if (adopter) return adopter.firstName + ' ' + adopter.lastName;
			const provider = providers.find(p => p.userId === userId);
			if (provider) return provider.orgName;
			return 'Unknown';
		};

		const allMessages = [
			...inbox.map(msg => ({ 
				...msg, 
				direction: 'Received', 
				senderName: getName(msg.senderId),
				receiverName: getName(msg.receiverId)
			})),
			...sent.map(msg => ({ 
				...msg, 
				direction: 'Sent', 
				senderName: getName(msg.senderId),
				receiverName: getName(msg.receiverId)
			}))
		];

		return allMessages.sort((a, b) => new Date(b.sentAt) - new Date(a.sentAt));
	}
}

